package com.izonehub.stores.auth;import org.junit.jupiter.api.Test;import static org.assertj.core.api.Assertions.assertThat;class PasswordPolicyTest{@Test void enforcesLengthNumberAndSpecialCharacter(){PasswordPolicy p=new PasswordPolicy();assertThat(p.isValid("weak")).isFalse();assertThat(p.isValid("Password1")).isFalse();assertThat(p.isValid("Password!")).isFalse();assertThat(p.isValid("Password1!")).isTrue();}}
